// build.gradle: implementation 'org.springframework.boot:spring-boot-starter-data-redis'

// application.yaml:
// spring:
//   data:
//     redis:
//       host: redis.default.svc.cluster.local
//       port: 6379

// ============ 1. CACHE — Spring Cache abstraction over Redis ============
@Configuration
@EnableCaching
public class RedisConfig {
  @Bean
  RedisCacheManager cacheManager(RedisConnectionFactory factory) {
    var config = RedisCacheConfiguration.defaultCacheConfig()
        .entryTtl(Duration.ofMinutes(10))                  // default TTL
        .disableCachingNullValues()
        .serializeValuesWith(SerializationPair.fromSerializer(
            new GenericJackson2JsonRedisSerializer()));
    return RedisCacheManager.builder(factory)
        .cacheDefaults(config)
        .withCacheConfiguration("userProfiles", config.entryTtl(Duration.ofHours(1)))
        .build();
  }
}

@Service
public class UserService {
  // Auto-caches by userId. First call hits DB; subsequent calls hit Redis.
  @Cacheable(cacheNames = "userProfiles", key = "#userId")
  public User getUser(long userId) {
    return userRepo.findById(userId).orElseThrow();
  }

  // Invalidate the cache on update.
  @CacheEvict(cacheNames = "userProfiles", key = "#user.id")
  public User updateUser(User user) {
    return userRepo.save(user);
  }
}

// ============ 2. RATE LIMITER — sliding-window with sorted sets ============
@Component
public class RateLimiter {
  private final StringRedisTemplate redis;

  public RateLimiter(StringRedisTemplate redis) { this.redis = redis; }

  // Allow N requests per WINDOW seconds. Uses ZADD + ZREMRANGEBYSCORE + ZCARD.
  public boolean allow(String key, int limit, int windowSeconds) {
    long now = System.currentTimeMillis();
    long windowStart = now - windowSeconds * 1000L;

    // Remove old entries
    redis.opsForZSet().removeRangeByScore(key, 0, windowStart);
    // Count entries in the current window
    Long count = redis.opsForZSet().zCard(key);

    if (count != null && count >= limit) {
      return false;   // over the limit
    }
    // Add this request timestamp (score = timestamp)
    redis.opsForZSet().add(key, String.valueOf(now), now);
    redis.expire(key, Duration.ofSeconds(windowSeconds + 5));
    return true;
  }
}

// Usage: if (!rateLimiter.allow("login:" + ip, 5, 60)) throw new TooManyRequests();

// ============ 3. DISTRIBUTED LOCK — SET with NX + EX ============
public class DistributedLock {
  private final StringRedisTemplate redis;
  private final String key;
  private final String token;    // random per instance — prevents accidental release

  public boolean tryAcquire(Duration ttl) {
    return Boolean.TRUE.equals(redis.opsForValue().setIfAbsent(key, token, ttl));
    //  SET key token NX EX 30 — atomic, expires so a crashed holder doesn't deadlock
  }

  public void release() {
    // Atomic check-and-delete via Lua: only delete if we still hold the lock.
    String script = "if redis.call('get', KEYS[1]) == ARGV[1] then return redis.call('del', KEYS[1]) else return 0 end";
    redis.execute(new DefaultRedisScript<>(script, Long.class), List.of(key), token);
  }
}
